// yieldWasm was generated by the following:
//
//	cd testdata; wasm-tools parse yield.wat -o yield.wasm
//
//go:embed testdata/yield.wasm
var yieldWasm []byte

type engineConfig struct {
	name string
	cfg  wazero.RuntimeConfig
}

func engineConfigs() []engineConfig {
	return []engineConfig{
		{"interpreter", wazero.NewRuntimeConfigInterpreter()},
		{"compiler", wazero.NewRuntimeConfigCompiler()},
	}
}

type observingTimeProvider struct {
	nanotime func() int64
}

func newObservingTimeProvider() observingTimeProvider {
	return observingTimeProvider{nanotime: platform.NewFakeNanotime()}
}

func (p observingTimeProvider) Walltime() (int64, int32) { return 0, 0 }
func (p observingTimeProvider) Nanotime() int64          { return p.nanotime() }
func (p observingTimeProvider) Nanosleep(int64)          {}

type recordingYieldObserver struct {
	mu           sync.Mutex
	observations []experimental.YieldObservation
}

func (r *recordingYieldObserver) ObserveYield(_ context.Context, observation experimental.YieldObservation) {
	r.mu.Lock()
	defer r.mu.Unlock()
	r.observations = append(r.observations, observation)
}

func (r *recordingYieldObserver) snapshot() []experimental.YieldObservation {
	r.mu.Lock()
	defer r.mu.Unlock()
	return append([]experimental.YieldObservation(nil), r.observations...)
}

// yieldingHostFunc is a GoModuleFunction that yields execution.
type yieldingHostFunc struct{ t *testing.T }

func (f *yieldingHostFunc) Call(ctx context.Context, mod api.Module, stack []uint64) {
	yielder := experimental.GetYielder(ctx)
	if yielder == nil {
		f.t.Fatal("expected yielder in context")
	}
	yielder.Yield()
	// Unreachable after Yield().
}

func setupYieldTest(t *testing.T, cfg wazero.RuntimeConfig) (api.Module, wazero.Runtime, context.Context) {
	return setupYieldTestWithHost(t, cfg, &yieldingHostFunc{t: t})
}

func setupYieldTestWithHost(t *testing.T, cfg wazero.RuntimeConfig, host api.GoModuleFunction) (api.Module, wazero.Runtime, context.Context) {
	t.Helper()
	ctx := context.Background()
	rt := wazero.NewRuntimeWithConfig(ctx, cfg)

	_, err := rt.NewHostModuleBuilder("example").
		NewFunctionBuilder().
		WithGoModuleFunction(host,
			nil,                                // no params
			[]api.ValueType{api.ValueTypeI32}). // 1 i32 result
		Export("async_work").
		Instantiate(ctx)
	require.NoError(t, err)

	mod, err := rt.Instantiate(ctx, yieldWasm)
	require.NoError(t, err)

	return mod, rt, ctx
}

func setupYieldResultCountChangeTest(t *testing.T, cfg wazero.RuntimeConfig) (api.Module, wazero.Runtime, context.Context) {
	t.Helper()
	ctx := context.Background()
	rt := wazero.NewRuntimeWithConfig(ctx, cfg)

	builder := rt.NewHostModuleBuilder("example")
	builder.NewFunctionBuilder().
		WithGoModuleFunction(&yieldingHostFunc{t: t},
			nil,
			[]api.ValueType{api.ValueTypeI32}).
		Export("async_one")
	builder.NewFunctionBuilder().
		WithGoModuleFunction(&yieldingHostFunc{t: t},
			nil,
			[]api.ValueType{api.ValueTypeI32, api.ValueTypeI32}).
		Export("async_two")
	_, err := builder.Instantiate(ctx)
	require.NoError(t, err)

	mod, err := rt.Instantiate(ctx, yieldDifferentResultCountsWasm())
	require.NoError(t, err)

	return mod, rt, ctx
}

func requireYieldError(t *testing.T, err error) *experimental.YieldError {
	t.Helper()
	var yieldErr *experimental.YieldError
	require.True(t, errors.As(err, &yieldErr), "expected YieldError, got: %v", err)
	require.NotNil(t, yieldErr.Resumer())
	return yieldErr
}

func TestYield_BasicYieldAndResume(t *testing.T) {
	for _, ec := range engineConfigs() {
		t.Run(ec.name, func(t *testing.T) {
			mod, rt, ctx := setupYieldTest(t, ec.cfg)
			defer rt.Close(ctx)

			yieldCtx := experimental.WithYielder(ctx)
			_, err := mod.ExportedFunction("run").Call(yieldCtx)

			yieldErr := requireYieldError(t, err)
			resumer := yieldErr.Resumer()

			results, err := resumer.Resume(experimental.WithYielder(ctx), []uint64{42})
			require.NoError(t, err)
			require.Equal(t, uint64(142), results[0]) // 42 + 100
		})
	}
}

func TestYield_ResumeFromDifferentGoroutine(t *testing.T) {
	for _, ec := range engineConfigs() {
		t.Run(ec.name, func(t *testing.T) {
			mod, rt, ctx := setupYieldTest(t, ec.cfg)
			defer rt.Close(ctx)

			yieldCtx := experimental.WithYielder(ctx)
			_, err := mod.ExportedFunction("run").Call(yieldCtx)

			yieldErr := requireYieldError(t, err)

			var wg sync.WaitGroup
			var results []uint64
			var resumeErr error
			wg.Add(1)
			go func() {
				defer wg.Done()
				results, resumeErr = yieldErr.Resumer().Resume(experimental.WithYielder(ctx), []uint64{7})
			}()
			wg.Wait()

			require.NoError(t, resumeErr)
			require.Equal(t, uint64(107), results[0]) // 7 + 100
		})
	}
}

func TestYield_Cancel(t *testing.T) {
	for _, ec := range engineConfigs() {
		t.Run(ec.name, func(t *testing.T) {
			mod, rt, ctx := setupYieldTest(t, ec.cfg)
			defer rt.Close(ctx)

			yieldCtx := experimental.WithYielder(ctx)
			_, err := mod.ExportedFunction("run").Call(yieldCtx)

			yieldErr := requireYieldError(t, err)
			resumer := yieldErr.Resumer()

			resumer.Cancel()
			resumer.Cancel() // idempotent

			_, err = resumer.Resume(experimental.WithYielder(ctx), []uint64{42})
			require.Error(t, err)
			require.Contains(t, err.Error(), "cancelled")
		})
	}
}

func TestYield_CancelDoesNotNotifyTrapObserver(t *testing.T) {
	for _, ec := range engineConfigs() {
		t.Run(ec.name, func(t *testing.T) {
			mod, rt, ctx := setupYieldTest(t, ec.cfg)
			defer rt.Close(ctx)

			observer := &recordingTrapObserver{}
			_, err := mod.ExportedFunction("run").Call(
				experimental.WithTrapObserver(experimental.WithYielder(ctx), observer),
			)

			resumer := requireYieldError(t, err).Resumer()
			resumer.Cancel()

			require.Zero(t, observer.count())

			_, err = resumer.Resume(experimental.WithYielder(ctx), []uint64{42})
			require.EqualError(t, err, "cannot resume: resumer has been cancelled")
			require.Zero(t, observer.count())
		})
	}
}

func TestYield_ResumeRejectsWrongHostResultCount(t *testing.T) {
	for _, ec := range engineConfigs() {
		t.Run(ec.name, func(t *testing.T) {
			for _, tc := range []struct {
				name        string
				hostResults []uint64
			}{
				{name: "too few", hostResults: nil},
				{name: "too many", hostResults: []uint64{1, 2}},
			} {
				t.Run(tc.name, func(t *testing.T) {
					mod, rt, ctx := setupYieldTest(t, ec.cfg)
					defer rt.Close(ctx)

					_, err := mod.ExportedFunction("run").Call(experimental.WithYielder(ctx))
					resumer := requireYieldError(t, err).Resumer()

					_, err = resumer.Resume(experimental.WithYielder(ctx), tc.hostResults)
					require.EqualError(t, err, fmt.Sprintf("cannot resume: expected 1 host results, but got %d", len(tc.hostResults)))

					results, err := resumer.Resume(experimental.WithYielder(ctx), []uint64{42})
					require.NoError(t, err)
					require.Equal(t, []uint64{142}, results)
				})
			}
		})
	}
}

