func TestYield_ResumeUsesResumedTrapObserver(t *testing.T) {
	for _, ec := range engineConfigs() {
		t.Run(ec.name, func(t *testing.T) {
			mod, rt, ctx := setupYieldTest(t, ec.cfg)
			defer rt.Close(ctx)

			initialObserver := &recordingTrapObserver{}
			_, err := mod.ExportedFunction("run_twice").Call(
				experimental.WithTrapObserver(experimental.WithYielder(ctx), initialObserver),
			)
			resumer := requireYieldError(t, err).Resumer()

			resumeObserver := &recordingTrapObserver{}
			resumeCtx := experimental.WithTrapObserver(
				experimental.WithHostCallPolicy(
					experimental.WithYielder(ctx),
					experimental.HostCallPolicyFunc(func(context.Context, api.Module, api.FunctionDefinition) bool {
						return false
					}),
				),
				resumeObserver,
			)

			_, err = resumer.Resume(resumeCtx, []uint64{1})
			require.True(t, errors.Is(err, wasmruntime.ErrRuntimePolicyDenied), "expected ErrRuntimePolicyDenied, got %v", err)
			require.Zero(t, initialObserver.count())

			observation := resumeObserver.single(t)
			require.Equal(t, experimental.TrapCausePolicyDenied, observation.Cause)
			require.True(t, errors.Is(observation.Err, wasmruntime.ErrRuntimePolicyDenied))
			require.Equal(t, mod.Name(), observation.Module.Name())
		})
	}
}

func TestYield_ConcurrentResumePanicsSecondCaller(t *testing.T) {
	type resumeOutcome struct {
		results  []uint64
		err      error
		panicErr error
	}

	for _, ec := range engineConfigs() {
		t.Run(ec.name, func(t *testing.T) {
			mod, rt, ctx := setupYieldTest(t, ec.cfg)
			defer rt.Close(ctx)

			_, err := mod.ExportedFunction("run").Call(experimental.WithYielder(ctx))
			resumer := requireYieldError(t, err).Resumer()

			start := make(chan struct{})
			outcomes := make(chan resumeOutcome, 2)

			for i := 0; i < 2; i++ {
				go func() {
					<-start
					var outcome resumeOutcome
					outcome.panicErr = require.CapturePanic(func() {
						outcome.results, outcome.err = resumer.Resume(experimental.WithYielder(ctx), []uint64{7})
					})
					outcomes <- outcome
				}()
			}

			close(start)
			first := <-outcomes
			second := <-outcomes

			var panicOutcome, successOutcome resumeOutcome
			switch {
			case first.panicErr != nil && second.panicErr == nil:
				panicOutcome, successOutcome = first, second
			case second.panicErr != nil && first.panicErr == nil:
				panicOutcome, successOutcome = second, first
			default:
				t.Fatalf("expected one panic and one success, got first=%+v second=%+v", first, second)
			}

			require.Contains(t, panicOutcome.panicErr.Error(), "Resume called more than once")
			require.NoError(t, successOutcome.err)
			require.Equal(t, []uint64{107}, successOutcome.results)
		})
	}
}

func TestYieldObserver_Lifecycle(t *testing.T) {
	for _, ec := range engineConfigs() {
		t.Run(ec.name, func(t *testing.T) {
			provider := newObservingTimeProvider()
			mod, rt, ctx := setupYieldTest(t, ec.cfg.WithTimeProvider(provider))
			defer rt.Close(ctx)

			observer := &recordingYieldObserver{}
			_, err := mod.ExportedFunction("run").Call(
				experimental.WithYieldObserver(experimental.WithYielder(ctx), observer),
			)
			resumer := requireYieldError(t, err).Resumer()

			results, err := resumer.Resume(experimental.WithYielder(ctx), []uint64{42})
			require.NoError(t, err)
			require.Equal(t, []uint64{142}, results)

			observations := observer.snapshot()
			require.Equal(t, 2, len(observations))
			require.Equal(t, experimental.YieldEventYielded, observations[0].Event)
			require.Equal(t, uint64(1), observations[0].YieldCount)
			require.Equal(t, 1, observations[0].ExpectedHostResults)
			require.Equal(t, int64(0), observations[0].SuspendedNanos)
			require.Equal(t, experimental.YieldEventResumed, observations[1].Event)
			require.Equal(t, uint64(1), observations[1].YieldCount)
			require.Equal(t, 1, observations[1].ExpectedHostResults)
			require.Equal(t, int64(1_000_000), observations[1].SuspendedNanos)
		})
	}
}

func TestYieldObserver_Cancel(t *testing.T) {
	for _, ec := range engineConfigs() {
		t.Run(ec.name, func(t *testing.T) {
			provider := newObservingTimeProvider()
			mod, rt, ctx := setupYieldTest(t, ec.cfg.WithTimeProvider(provider))
			defer rt.Close(ctx)

			observer := &recordingYieldObserver{}
			_, err := mod.ExportedFunction("run").Call(
				experimental.WithYieldObserver(experimental.WithYielder(ctx), observer),
			)
			resumer := requireYieldError(t, err).Resumer()

			resumer.Cancel()
			resumer.Cancel()

			observations := observer.snapshot()
			require.Equal(t, 2, len(observations))
			require.Equal(t, experimental.YieldEventYielded, observations[0].Event)
			require.Equal(t, experimental.YieldEventCancelled, observations[1].Event)
			require.Equal(t, uint64(1), observations[1].YieldCount)
			require.Equal(t, 1, observations[1].ExpectedHostResults)
			require.Equal(t, int64(1_000_000), observations[1].SuspendedNanos)
		})
	}
}

func TestYieldObserver_ReyieldAndValidation(t *testing.T) {
	for _, ec := range engineConfigs() {
		t.Run(ec.name, func(t *testing.T) {
			provider := newObservingTimeProvider()
			mod, rt, ctx := setupYieldTest(t, ec.cfg.WithTimeProvider(provider))
			defer rt.Close(ctx)

			observer := &recordingYieldObserver{}

			_, err := mod.ExportedFunction("run").Call(
				experimental.WithYieldObserver(experimental.WithYielder(ctx), observer),
			)
			resumer := requireYieldError(t, err).Resumer()

			_, err = resumer.Resume(experimental.WithYielder(ctx), nil)
			require.EqualError(t, err, "cannot resume: expected 1 host results, but got 0")
			require.Equal(t, 1, len(observer.snapshot()))

			_, err = mod.ExportedFunction("run_twice").Call(
				experimental.WithYieldObserver(experimental.WithYielder(ctx), observer),
			)
			firstResumer := requireYieldError(t, err).Resumer()

			_, err = firstResumer.Resume(experimental.WithYielder(ctx), []uint64{40})
			secondYield := requireYieldError(t, err)

			results, err := secondYield.Resumer().Resume(experimental.WithYielder(ctx), []uint64{2})
			require.NoError(t, err)
			require.Equal(t, []uint64{42}, results)

			observations := observer.snapshot()
			require.Equal(t, 5, len(observations))
			require.Equal(t, experimental.YieldEventYielded, observations[0].Event)
			require.Equal(t, experimental.YieldEventYielded, observations[1].Event)
			require.Equal(t, uint64(1), observations[1].YieldCount)
			require.Equal(t, experimental.YieldEventResumed, observations[2].Event)
			require.Equal(t, uint64(1), observations[2].YieldCount)
			require.Equal(t, experimental.YieldEventYielded, observations[3].Event)
			require.Equal(t, uint64(2), observations[3].YieldCount)
			require.Equal(t, experimental.YieldEventResumed, observations[4].Event)
			require.Equal(t, uint64(2), observations[4].YieldCount)
		})
	}
}

func TestYield_WithoutEnable(t *testing.T) {
	ctx := context.Background()
	if got := experimental.GetYielder(ctx); got != nil {
		t.Fatal("expected nil yielder when not enabled")
	}
}

func TestYield_ErrorIsYielded(t *testing.T) {
	ye := experimental.NewYieldError(nil)
	if !errors.Is(ye, experimental.ErrYielded) {
		t.Fatal("errors.Is(YieldError, ErrYielded) should be true")
	}
}

func yieldDifferentResultCountsWasm() []byte {
	return binaryencoding.EncodeModule(&wasm.Module{
		TypeSection: []wasm.FunctionType{
			{Results: []api.ValueType{api.ValueTypeI32}},
			{Results: []api.ValueType{api.ValueTypeI32, api.ValueTypeI32}},
			{},
		},
		ImportSection: []wasm.Import{
			{Module: "example", Name: "async_one", Type: wasm.ExternTypeFunc, DescFunc: 0},
			{Module: "example", Name: "async_two", Type: wasm.ExternTypeFunc, DescFunc: 1},
		},
		FunctionSection: []wasm.Index{2},
		CodeSection: []wasm.Code{{
			Body: []byte{
				wasm.OpcodeCall, 0,
				wasm.OpcodeDrop,
				wasm.OpcodeCall, 1,
				wasm.OpcodeDrop,
				wasm.OpcodeDrop,
				wasm.OpcodeEnd,
			},
		}},
		ExportSection: []wasm.Export{{Type: api.ExternTypeFunc, Name: "run", Index: 2}},
	})
}
